UPDATE public.training_items ti
SET title = 'Säljguide: Företagshemsida',
    body = $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "När du använder den"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "För etablerade företag och tjänsteföretag som vill se trovärdiga ut, få in fler förfrågningar och kunna uppdatera sajten själva. Särskilt stark när kunden har en gammal eller långsam sajt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öppning (krok)"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Era kunder bestämmer sig på tre sekunder om de stannar eller klickar vidare. Får jag fråga – hur många förfrågningar drar er nuvarande sajt in i månaden?"}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Behovsfrågor"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Hur får ni in nya kunder idag?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Vad skulle ni vilja att hemsidan gjorde som den inte gör nu?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Vem uppdaterar sajten idag och hur ofta?"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pitchen"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Problem: "}, {"type": "text", "text": "En daterad eller långsam sajt skickar kunder rakt till konkurrenten – affärer ni aldrig ens får veta att ni förlorade."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Lösning: "}, {"type": "text", "text": "En snabb, snygg och säljande sajt ni är stolta över, med eget CMS så ni uppdaterar den själva."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Resultat: "}, {"type": "text", "text": "Fler förfrågningar från rätt kunder, och en sajt som jobbar för er dygnet runt."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här ingår"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Upp till sju sidor"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Responsiv design för mobil, surfplatta och dator"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Eget CMS – inga utvecklarkunskaper behövs"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "On-page SEO och Google Analytics"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Kontaktformulär och koppling till sociala medier"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Värde och ROI"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tänk på sajten som er bästa säljare – den jobbar dygnet runt och kostar 18 000 kr en gång. En extra kund i månaden och den är betald flera gånger om."}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Invändningar för det här paketet"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "\"Vi har redan en hemsida.\""}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Vad bra, då har ni grunden. Hur många leads drar den in i månaden? Många sajter är snygga broschyrer men säljer inte – jag kan visa var ni tappar besökare."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "\"Det är för dyrt.\""}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Det är en investering. Vad är en ny kund värd för er? En extra i månaden och sajten är betald. Vi kan också börja i en enklare nivå."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "\"Kan vi inte fixa det själva i Wix?\""}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Visst kan ni, men ni betalar med er tid och får sällan fart, SEO och konvertering på köpet. Vi bygger det rätt från start så ni kan lägga tiden på era kunder."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Avslut"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Det här är vårt populäraste paket, och det är ingen slump. Ska jag visa ett par exempel och ta fram ett förslag till på fredag?"}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pris"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "18 000 kr engångs. Tillägg: extra sidor, copywriting, fotografering, löpande SEO."}]}]}$j$::jsonb
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'saljmanus'
  AND ti.title = 'Säljpitch: Företagshemsida';

